const now = new Date().toISOString();

const conversationId = $json.conversationId;
const phone = $json.phone;
if (!phone) return [];

const greeting = $json.greeting;

const smsBody = `${greeting} Tyler from [Company], just circling back here.

We’re about to launch our fishing charter campaign in San Diego and are getting the last few captains set up before it goes live. Would love to have you onboard.

Would you be open to a quick chat?`;

return [{
  json: {
    body: smsBody,
    channel: "sms",
    conversation: conversationId,
    from: "YOUR_PHONE_NUMBER",
    to: phone,
    sendAt: now,
    payload: {
      draftJs: {
        blocks: [{ text: smsBody, key: "abc123", type: "unstyled", depth: 0, data: {}, inlineStyleRanges: [], entityRanges: [] }],
        entityMap: {}
      }
    }
  }
}];

const now = new Date().toISOString();

// Conversation ID
const conversationId =
  $json?.data?.id ||
  $json?.conversationId ||
  $node["Create Conversation20"]?.json?.data?.id;

// Row data
const row = $json;

// Email
const emailRaw = row.Email ?? row.EMAIL ?? "";
const email = String(emailRaw).trim();

// If there's no email, SKIP sending email for this owner
if (!email) return [];

// Use greeting from upstream node if it already exists
let greetingLine = row.greeting;

// Fallback: build greeting from CONTACT_NAME
if (!greetingLine) {
  const rawName = String(row.CONTACT_NAME ?? "").trim();
  const nameParts = rawName.split(/\s+/);

  let displayName = "";

  if (/^(capt\.?|captain)$/i.test(nameParts[0]) && nameParts.length > 1) {
    displayName = `${nameParts[0]} ${nameParts[1]}`;
  } else {
    displayName = nameParts[0] || "";
  }

  greetingLine = displayName ? `Hello ${displayName},` : "Hello,";
}

// Optional "to.name"
const toObj = email ? { email } : null;

const emailBody = `${greetingLine}

Just wanted to circle back on my previous message.

We’re about to launch our fishing charter campaign in San Diego and are getting the last few captains and operators set up on the platform before it goes live. 

I’d love to include you so you can benefit from the additional exposure. 

Would you be open to a quick call to see if it makes sense?

Best,
Tyler`;

const subject = "Quick question about your charter";

return [
  {
    json: {
      body: emailBody,
      channel: "email",
      conversation: conversationId,
      from: {
        email: "fishingteam@[company].com",
        name: "[Company] Fishing Team",
      },
      to: toObj,
      subject,
      sendAt: now,
      payload: {
        draftJs: {
          blocks: [
            {
              text: emailBody,
              key: "abc123",
              type: "unstyled",
              depth: 0,
              data: {},
              inlineStyleRanges: [],
              entityRanges: [],
            },
          ],
          entityMap: {},
        },
      },
    },
  },
];

